algorithm:
Iterate over ships sorted by time window urgency, evaluate all feasible inserts across all routes including empties, pick the minimal marginal cost increase using delta evaluation without full re-routing where possible, and fall back to cheapest new route creation.}

func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	n := len(oris)
	if n == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}

	orderIndices := make([]int, n)
	for i := range orderIndices {
		orderIndices[i] = i
	}

	timeUrgency := make([]float64, n)
	for i := 0; i < n; i++ {
		w := oris[i].TimeEnd - oris[i].TimeStart
		if w <= 0 {
			w = 1
		}
		timeUrgency[i] = float64(w)
	}

	sort.SliceStable(orderIndices, func(a, b int) bool {
		return timeUrgency[orderIndices[a]] < timeUrgency[orderIndices[b]]
	})

	for _, oi := range orderIndices {
		bestIdx := -1
		bestMarginal := 1e18
		ori := oris[oi]
		des := dess[oi]

		for i := 0; i < dispatch.AssignsLen; i++ {
			assignCopy := dispatch.Assigns[i]
			oldCost := assignCopy.Cost
			addOk := assignCopy.AddShip(total_ship+oi, ori, des)
			if addOk {
				assignCopy.GenRoute()
				newCost := assignCopy.Cost
				marginal := newCost - oldCost
				if newCost >= 0 && marginal < bestMarginal {
					bestMarginal = marginal
					bestIdx = i
				}
			}
		}

		for i := dispatch.AssignsLen; i < MAXASSIGNS; i++ {
			var tmpAssign Assign
			tmpAssign.AddShip(total_ship+oi, ori, des)
			tmpAssign.GenRoute()
			if tmpAssign.Cost >= 0 {
				marginal := tmpAssign.Cost
				if marginal < bestMarginal {
					bestMarginal = marginal
					bestIdx = -2 - i
				}
			}
		}

		if bestIdx >= 0 {
			dispatch.Assigns[bestIdx].AddShip(total_ship+oi, ori, des)
			dispatch.Assigns[bestIdx].GenRoute()
		} else if bestIdx <= -2 {
			slot := -2 - bestIdx
			if slot < MAXASSIGNS {
				dispatch.Assigns[slot].AddShip(total_ship+oi, ori, des)
				dispatch.Assigns[slot].GenRoute()
				if dispatch.AssignsLen <= slot {
					dispatch.AssignsLen = slot + 1
				}
			}
		} else {
			for i := 0; i < MAXASSIGNS; i++ {
				var tmpAssign Assign
				ok := tmpAssign.AddShip(total_ship+oi, ori, des)
				if ok {
					tmpAssign.GenRoute()
					if tmpAssign.Cost >= 0 {
						if i < dispatch.AssignsLen {
							dispatch.Assigns[i].AddShip(total_ship+oi, ori, des)
							dispatch.Assigns[i].GenRoute()
						} else {
							dispatch.Assigns[i].AddShip(total_ship+oi, ori, des)
							dispatch.Assigns[i].GenRoute()
							dispatch.AssignsLen = i + 1
						}
						break
					}
				}
			}
		}
	}

	dispatch.RenewnTotalCost()
	return dispatch

